# ── API — streaming ────────────────────────────────────────────────────────────
def stream_ollama(api_key, model, messages, temp, max_tok):
    """Generator that yields text tokens as they arrive."""
    try:
        r = requests.post(
            "https://ollama.com/api/chat",
            headers={"Authorization": f"Bearer {api_key}", "Content-Type": "application/json"},
            json={"model": model, "messages": messages, "stream": True,
                  "options": {"temperature": temp, "num_predict": max_tok}},
            timeout=120,
            stream=True,
        )
        r.raise_for_status()
        import json as _json
        for raw_line in r.iter_lines():
            if raw_line:
                try:
                    chunk = _json.loads(raw_line)
                    token = chunk.get("message", {}).get("content", "")
                    if token:
                        yield token
                    if chunk.get("done"):
                        break
                except Exception:
                    continue
    except requests.exceptions.HTTPError as e:
        code = e.response.status_code
        if code == 401: yield "Invalid API key. Go to ollama.com → Settings → API Keys."
        elif code == 404: yield f"Model `{model}` is not available on Ollama cloud."
        else: yield f"HTTP {code}: {e.response.text[:300]}"
    except requests.exceptions.ConnectionError:
        yield "Cannot reach Ollama API. Check your internet connection."
    except Exception as e:
        yield f"Error: {e}"

