# Empty state
if not st.session_state.chats[st.session_state.current_chat]:
    st.markdown("""
    <div style="text-align:center; padding:80px 0 60px;">
        <div style="font-family:'Inter',sans-serif;font-size:22px;font-weight:500;color:#3a3a3a;margin-bottom:10px;">
            How can I help you today?
        </div>
        <div style="font-family:'Inter',sans-serif;font-size:13px;color:#444;">
            Select a model and start a conversation.
        </div>
    </div>
    """, unsafe_allow_html=True)

# Display chat history for current chat
for msg in st.session_state.chats[st.session_state.current_chat]:
    with st.chat_message(msg["role"]):
        st.markdown(msg["content"])

# Input bar — text, speech-to-text (mic), file upload
prompt = st.chat_input(
    "Say something, record audio (speech-to-text), or attach a file",
    accept_audio=True,
    accept_file=True,
    file_type=["txt", "pdf", "json", "py", "csv"],
)

if prompt:
    user_text    = ""
    file_context = ""

    if prompt.text:
        user_text = prompt.text

    if prompt.files:
        for f in prompt.files:
            try:
                raw = f.read()
                file_str = raw.decode("utf-8", errors="replace")
                file_context += f"\n\n[Attached file: {f.name}]\n```\n{file_str[:4000]}\n```"
            except Exception as e:
                file_context += f"\n\n[Could not read {f.name}: {e}]"

    if not user_text and not file_context:
        st.stop()

    display_text      = user_text if user_text else "(file attached)"
    full_user_content = user_text + file_context

    st.session_state.chats[st.session_state.current_chat].append(
        {"role": "user", "content": full_user_content}
    )
    with st.chat_message("user"):
        st.markdown(display_text)
        if file_context:
            st.caption(f"📎 {', '.join(f.name for f in prompt.files)}")

    api_msgs = [{"role": "system", "content": SYS_INSTR}] + [
        {"role": m["role"], "content": m["content"]}
        for m in st.session_state.chats[st.session_state.current_chat]
    ]

    with st.chat_message("assistant"):
        reply_box  = st.empty()
        full_reply = ""
        for token in stream_ollama(st.session_state.api_key, model_id, api_msgs, TEMPERATURE, MAX_TOKENS):
            full_reply += token
            reply_box.markdown(full_reply + "▌")
        reply_box.markdown(full_reply)

    st.session_state.chats[st.session_state.current_chat].append(
        {"role": "assistant", "content": full_reply}
    )